// Split Atom Entries (Run once for all items)
// Input: many items, each item is parsed XML JSON for ONE subreddit feed
// Output: one item per post entry, across ALL feeds

const nowIso = new Date().toISOString();
const out = [];

for (const item of $input.all()) {
  const j = item.json;

  // Atom feeds from Reddit usually look like { feed: { ... entry: [...] } }
  const feed = j.feed ?? j.rss ?? j;
  const entriesRaw = feed?.entry ?? [];

  const entries = Array.isArray(entriesRaw) ? entriesRaw : [entriesRaw];

  // Try to infer subreddit name
  const subreddit =
    feed?.category?.label?.replace(/^r\//, "") ||
    feed?.title?.replace(/^newest submissions :\s*/i, "") ||
    j.subreddit ||
    j.subreddit_key ||
    "unknown";

  for (const e of entries) {
    // Link can be object or array depending on parser
    let url = "";
    if (typeof e?.link === "string") url = e.link;
    else if (e?.link?.href) url = e.link.href;
    else if (Array.isArray(e?.link)) {
      url =
        e.link.find((l) => l?.rel === "alternate")?.href ||
        e.link.find((l) => l?.href)?.href ||
        "";
    }

    out.push({
      json: {
        subreddit,
        subreddit_key: subreddit,
        title: e?.title ?? "",
        url,
        published: e?.published ?? e?.updated ?? "",
        author: e?.author?.name ?? "",
        post_id: e?.id ?? "",
        date_found: nowIso,
        // keep raw entry if you want for later debugging
        // _raw: e,
      },
    });
  }
}

return out;

function norm(s) {
  return (s ?? '')
    .toString()
    .toLowerCase()
    .replace(/[\u2010-\u2015]/g, '-') // normalize dash variants
    .replace(/\s+/g, ' ')
    .trim();
}

const all = $input.all().map(i => i.json);

// Keyword rows have include/exclude columns
const keywordRows = all.filter(r => ('include' in r) || ('exclude' in r));
const postsRaw = all.filter(r => !('include' in r) && !('exclude' in r));

const includeList = keywordRows.map(r => norm(r.include)).filter(Boolean);
const excludeList = keywordRows.map(r => norm(r.exclude)).filter(Boolean);

function findHits(text, list) {
  const hits = [];
  for (const k of list) if (k && text.includes(k)) hits.push(k);
  return hits;
}

const painPhrases = [
  "losing track",
  "too many messages",
  "forgot to follow up",
  "missed follow up",
  "fell through the cracks",
  "keep forgetting",
  "hard to keep track",
  "overwhelmed",
];

const W = {
  includeHit: 12,
  titleHitBonus: 8,
  questionBonus: 6,
  painBonus: 10,
};

// Try to derive subreddit/source key from a few common shapes
function getSubKey(p) {
  // preferred: explicit field you add in Normalize
  const direct =
    p.subreddit ||
    p.subreddit_name ||
    p.source ||
    p.source_name ||
    p.category_label ||
    p.category?.label ||
    p.feed_title ||
    '';

  let s = (direct ?? '').toString().trim();

  // if it's like "r/SaaS", keep that
  if (s) return s;

  // last resort: try parsing from URL
  const href = p.url || p.link?.href || '';
  const m = href.toString().match(/reddit\.com\/r\/([^/]+)\//i);
  if (m && m[1]) return `r/${m[1]}`;

  return 'unknown';
}

function parseTime(p) {
  // prefer published then updated
  const t = p.published || p.updated || p.date || p.date_found || '';
  const d = new Date(t);
  return isNaN(d.getTime()) ? 0 : d.getTime();
}

// Score posts
const scored = postsRaw.map(p => {
  const titleRaw = (p.title ?? '').toString();
  const title = norm(p.title);
  const body = norm(p.content_html || p.content || '');
  const text = `${title} ${body}`.trim();

  // hard exclude
  const excludeHits = findHits(text, excludeList);
  if (excludeHits.length > 0) return null;

  const includeHits = findHits(text, includeList);

  let score = 0;
  score += includeHits.length * W.includeHit;

  for (const k of includeHits) if (title.includes(k)) score += W.titleHitBonus;
  if (titleRaw.includes('?')) score += W.questionBonus;

  for (const pz of painPhrases) {
    if (text.includes(pz)) {
      score += W.painBonus;
      break;
    }
  }

  const subKey = getSubKey(p);
  const ts = parseTime(p);

  return {
    ...p,
    score,
    include_hits: includeHits.join(', '),
    exclude_hits: excludeHits.join(', '),
    subreddit_key: subKey,
    sort_ts: ts,
  };
}).filter(Boolean);

// Start permissive; tighten later if needed
const MIN_SCORE = 1;
const candidates = scored.filter(p => p.score >= MIN_SCORE);

// Group by subreddit_key
const groups = new Map();
for (const p of candidates) {
  const k = p.subreddit_key || 'unknown';
  if (!groups.has(k)) groups.set(k, []);
  groups.get(k).push(p);
}

// Take top 5 per subreddit (sort by score desc, then recency desc)
const TOP_N = 5;
const out = [];
for (const [k, arr] of groups.entries()) {
  arr.sort((a, b) => {
    if (b.score !== a.score) return b.score - a.score;
    return (b.sort_ts || 0) - (a.sort_ts || 0);
  });
  out.push(...arr.slice(0, TOP_N));
}

// Optional: sort final list by score/recency so your digest looks good
out.sort((a, b) => {
  if (b.score !== a.score) return b.score - a.score;
  return (b.sort_ts || 0) - (a.sort_ts || 0);
});

// Clean up helper fields if you don't want them in Output
// (leave subreddit_key if you want to group in your sheet)
return out.map(p => {
  const { sort_ts, ...rest } = p;
  return { json: rest };
});

const seenRows = $input.all().map(i => i.json);
const candidates = $node["Collect Candidates"].json.candidates || [];

const seen = new Set(
  seenRows.map(r => (r.post_id ?? '').toString().trim()).filter(Boolean)
);

const fresh = candidates.filter(c => {
  const id = (c.post_id ?? '').toString().trim();
  return id && !seen.has(id);
});

return fresh.map(x => ({ json: x }));

/**
 * n8n Code node (Run once for all items)
 * Builds ONE HTML email grouped by subreddit.
 *
 * Expected fields on each input item:
 * - title (string)
 * - post_url (string)   <-- REQUIRED for clickable title
 * - subreddit (string)
 * - score (number)
 * Optional:
 * - published_local (string)
 * - include_hits (string)
 */

function fmtChicago(iso) {
  const d = new Date(iso);
  if (isNaN(d.getTime())) return "";
  return d.toLocaleString("en-US", {
    timeZone: "America/Chicago",
    weekday: "short",
    month: "short",
    day: "2-digit",
    hour: "numeric",
    minute: "2-digit",
  });
}

function safeText(v) {
  // Basic HTML escaping so weird titles don't break the email
  const s = (v ?? "").toString();
  return s
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

const posts = $input.all().map((i) => i.json);

const nowIso = new Date().toISOString();
const dateLabel = fmtChicago(nowIso);

// If no posts, still send a friendly email
if (posts.length === 0) {
  return [
    {
      json: {
        subject: `[Subject] Reddit Digest — ${dateLabel} (no new posts)`,
        html: `
<div style="font-family: Arial, sans-serif; line-height: 1.4;">
  <h2 style="margin:0 0 8px;">📬 [Your company] Reddit Digest</h2>
  <p style="margin:0 0 12px; color:#444;">${safeText(dateLabel)}</p>
  <p style="margin:0; color:#444;">No new matching posts today.</p>
</div>`,
      },
    },
  ];
}

// Group by subreddit
const groups = {};
for (const p of posts) {
  const sub = (p.subreddit || "unknown").toString();
  if (!groups[sub]) groups[sub] = [];
  groups[sub].push(p);
}

// Sort each group by score (desc)
for (const sub of Object.keys(groups)) {
  groups[sub].sort((a, b) => (b.score || 0) - (a.score || 0));
}

// Sort subreddits by best score (desc)
const subredditKeys = Object.keys(groups).sort((a, b) => {
  const aTop = groups[a][0]?.score || 0;
  const bTop = groups[b][0]?.score || 0;
  return bTop - aTop;
});

// Build HTML
let html = `
<div style="font-family: Arial, sans-serif; line-height: 1.4;">
  <h2 style="margin:0 0 6px;">📬 [Your Company] Reddit Digest</h2>
  <p style="margin:0 0 14px;color:#444;">${safeText(dateLabel)} · ${posts.length} new posts</p>
  <hr style="border:none;border-top:1px solid #eee;margin:12px 0;" />
`;

// Build each subreddit section
for (const sub of subredditKeys) {
  html += `<h3 style="margin:16px 0 8px;">r/${safeText(sub)}</h3>`;
  html += `<ul style="padding-left:18px;margin:0;">`;

  for (const p of groups[sub]) {
    const title = safeText(p.title || "(no title)");
    const url = (p.url || p.post_url || p.link?.href || '').toString().trim(); // REQUIRED for clickable title
    const score = p.score ?? "";
    const when = p.published_local ? safeText(p.published_local) : "";
    const hits = p.include_hits ? safeText(p.include_hits) : "";

    // Fallback if URL missing (still show title, but not clickable)
   const titleHtml = url
  ? `<a href="${url}" target="_blank" style="text-decoration:none;color:#000;"><strong>${title}</strong></a>`
  : `<strong>${title}</strong>`;


    html += `
      <li style="margin:0 0 12px;">
        ${titleHtml}<br/>
        <span style="color:#666;font-size:12px;">
          score: ${safeText(score)}
          ${when ? ` · ${when}` : ``}
          ${hits ? ` · hits: ${hits}` : ``}
        </span>
      </li>
    `;
  }

  html += `</ul>`;
  html += `<hr style="border:none;border-top:1px solid #eee;margin:14px 0;" />`;
}

html += `</div>`;

return [
  {
    json: {
      subject: `[Your Company] Reddit Digest — ${dateLabel} (${posts.length} new)`,
      html,
    },
  },
];
